    Student* student = NULL;
    if (*head != NULL)
    {
        student = (*head)->info;
        Node* tmp = *head;
        if ((*head)->next != (*head))
        {
            tmp->prev->next = tmp->next;
            tmp->next->prev = tmp->prev;
